import http from 'node:http';
import { URL } from 'node:url';

function compilePath(pathname) {
  const keys = [];
  const pattern = pathname
    .split('/')
    .map((part) => {
      if (!part) return '';
      if (part.startsWith(':')) {
        keys.push(part.slice(1));
        return '([^/]+)';
      }
      return part.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    })
    .join('/');

  return {
    keys,
    regex: new RegExp(`^${pattern}$`)
  };
}

function decorateResponse(res) {
  res.status = (code) => {
    res.statusCode = code;
    return res;
  };

  res.set = (field, value) => {
    res.setHeader(field, value);
    return res;
  };

  res.json = (payload) => {
    if (!res.headersSent) res.setHeader('Content-Type', 'application/json; charset=utf-8');
    res.end(JSON.stringify(payload));
    return res;
  };

  res.send = (payload = '') => {
    if (typeof payload === 'object' && payload !== null && !Buffer.isBuffer(payload)) {
      return res.json(payload);
    }
    res.end(payload);
    return res;
  };

  return res;
}

function createApp() {
  const middlewares = [];
  const routes = [];

  const app = (req, res) => {
    decorateResponse(res);

    const parsedUrl = new URL(req.url, `http://${req.headers.host || '127.0.0.1'}`);
    req.path = parsedUrl.pathname;
    req.query = Object.fromEntries(parsedUrl.searchParams.entries());
    req.params = {};
    req.body = req.body ?? undefined;

    const stack = [...middlewares];
    const route = routes.find((entry) => entry.method === req.method && entry.regex.test(req.path));

    if (route) {
      const match = req.path.match(route.regex);
      route.keys.forEach((key, index) => {
        req.params[key] = decodeURIComponent(match[index + 1]);
      });
      stack.push(route.handler);
    } else {
      stack.push((_req, response) => {
        response.statusCode = 404;
        response.end('Not Found');
      });
    }

    let index = -1;
    const next = (err) => {
      if (err) {
        res.statusCode = 500;
        res.end(err.message || 'Internal Server Error');
        return;
      }

      index += 1;
      const layer = stack[index];
      if (!layer) return;

      try {
        const maybePromise = layer(req, res, next);
        if (maybePromise?.then) maybePromise.catch(next);
      } catch (error) {
        next(error);
      }
    };

    next();
  };

  app.use = (fn) => {
    middlewares.push(fn);
    return app;
  };

  app.disable = () => app;

  for (const method of ['GET', 'POST', 'PATCH', 'DELETE']) {
    app[method.toLowerCase()] = (pathname, handler) => {
      const { regex, keys } = compilePath(pathname);
      routes.push({ method, pathname, handler, regex, keys });
      return app;
    };
  }

  app.listen = (port, callback) => {
    const server = http.createServer(app);
    return server.listen(port, callback);
  };

  return app;
}

function json() {
  return (req, res, next) => {
    if (req.method === 'GET' || req.method === 'HEAD') {
      req.body = {};
      next();
      return;
    }

    const contentType = req.headers['content-type'] || '';
    if (!contentType.includes('application/json')) {
      req.body = {};
      next();
      return;
    }

    let raw = '';
    req.on('data', (chunk) => {
      raw += chunk;
    });
    req.on('end', () => {
      try {
        req.body = raw ? JSON.parse(raw) : {};
        next();
      } catch {
        res.statusCode = 400;
        res.setHeader('Content-Type', 'application/json; charset=utf-8');
        res.end(JSON.stringify({ message: 'JSON inválido.' }));
      }
    });
    req.on('error', next);
  };
}

createApp.json = json;
export default createApp;
